@patch
def build_constant_graph(self: SFMTLServer, lst_active_ids, comm_round):

    clients_sim_dict = {}
    num_active = len(lst_active_ids)
    graph = np.ones((num_active, num_active)) - np.eye(num_active)
    graph /= graph.sum(axis=1, keepdims=True)  # Normalize rows to sum to 1

    G = nx.complete_graph(num_active)
    for i in range(num_active):
        for j in range(i + 1, num_active):
            G.edges[i, j]['weight'] = round(graph[i][j], 4)
            clients_sim_dict[(i, j)] = round(graph[i][j], 4)
            
    for node, label in zip(list(range(num_active)), lst_active_ids):
        G.nodes[node]['label'] = label

    df_path = os.path.join(self.cfg.server.save_dir, str(comm_round), f"h_sim_df_{str(comm_round)}.pth")
    if not os.path.exists(os.path.dirname(df_path)):
        os.makedirs(os.path.dirname(df_path))
    torch.save(clients_sim_dict, df_path)

    return G, graph

